import uuid
from typing import Any, Dict, List, Optional

from mcp_proxy_adapter.commands.result import ErrorResult, SuccessResult

from .file_resolution import resolve_project_file_record
from ..base_mcp_command import BaseMCPCommand


def _is_valid_uuid4(value: Optional[str]) -> bool:
    """Return True if value is non-empty and valid UUID4 string; otherwise False."""
    if not value or not isinstance(value, str):
        return False
    s = value.strip()
    if not s:
        return False
    try:
        u = uuid.UUID(s, version=4)
        return str(u) == s
    except (ValueError, TypeError):
        return False
def _normalize_entities(rows: List[Dict[str, Any]]) -> List[Dict[str, Any]]:
    """
    Return all entities that have file_path (from JOIN).
    """
    return [dict(row) for row in rows if row.get("file_path")]


class GetCodeEntityInfoMCPCommand(BaseMCPCommand):
    """Get detailed information about a code entity (class, function, method)."""

    name = "get_code_entity_info"
    version = "1.0.0"
    descr = "Get detailed information about a class, function, or method"
    category = "ast"
    author = "Vasiliy Zdanovskiy"
    email = "vasilyvz@gmail.com"
    use_queue = False

    @classmethod
    def get_schema(cls) -> Dict[str, Any]:
        base_props = cls._get_base_schema_properties()
        return {
            "type": "object",
            "properties": {
                **base_props,
                "entity_type": {
                    "type": "string",
                    "description": "Type of entity: 'class', 'function', or 'method'",
                    "enum": ["class", "function", "method"],
                },
                "entity_name": {
                    "type": "string",
                    "description": "Name of the entity",
                },
                "file_path": {
                    "type": "string",
                    "description": "Optional file path to search in (relative to project root)",
                },
                "line": {
                    "type": "integer",
                    "description": "Optional line number for disambiguation",
                },
                "target_class": {
                    "type": "string",
                    "description": "Optional class name filter for method lookup",
                },
            },
            "required": ["project_id", "entity_type", "entity_name"],
            "additionalProperties": False,
        }

    async def execute(
        self,
        project_id: str,
        entity_type: str,
        entity_name: str,
        file_path: Optional[str] = None,
        line: Optional[int] = None,
        target_class: Optional[str] = None,
        **kwargs,
    ) -> SuccessResult:
        try:
            root_path = self._resolve_project_root(project_id)
            db = self._open_database()
            proj_id = project_id

            # Get entity info from database
            query = None
            params = []

            if entity_type == "class":
                query = "SELECT c.*, f.path as file_path FROM classes c JOIN files f ON c.file_id = f.id WHERE c.name = ? AND f.project_id = ?"
                params = [entity_name, proj_id]
                if file_path:
                    resolution = resolve_project_file_record(
                        db=db,
                        project_id=proj_id,
                        project_root=root_path,
                        file_path=file_path,
                    )
                    file_record = resolution["file_record"]
                    if not file_record:
                        db.disconnect()
                        return ErrorResult(
                            message=f"File not found in project: {file_path}",
                            code="FILE_NOT_FOUND",
                        )
                    query += " AND c.file_id = ?"
                    params.append(file_record["id"])
                if line:
                    query += " AND c.line = ?"
                    params.append(line)
            elif entity_type == "function":
                query = "SELECT func.*, f.path as file_path FROM functions func JOIN files f ON func.file_id = f.id WHERE func.name = ? AND f.project_id = ?"
                params = [entity_name, proj_id]
                if file_path:
                    resolution = resolve_project_file_record(
                        db=db,
                        project_id=proj_id,
                        project_root=root_path,
                        file_path=file_path,
                    )
                    file_record = resolution["file_record"]
                    if not file_record:
                        db.disconnect()
                        return ErrorResult(
                            message=f"File not found in project: {file_path}",
                            code="FILE_NOT_FOUND",
                        )
                    query += " AND func.file_id = ?"
                    params.append(file_record["id"])
                if line:
                    query += " AND func.line = ?"
                    params.append(line)
            elif entity_type == "method":
                query = "SELECT m.*, c.name as class_name, f.path as file_path FROM methods m JOIN classes c ON m.class_id = c.id JOIN files f ON c.file_id = f.id WHERE m.name = ? AND f.project_id = ?"
                params = [entity_name, proj_id]
                if file_path:
                    resolution = resolve_project_file_record(
                        db=db,
                        project_id=proj_id,
                        project_root=root_path,
                        file_path=file_path,
                    )
                    file_record = resolution["file_record"]
                    if not file_record:
                        db.disconnect()
                        return ErrorResult(
                            message=f"File not found in project: {file_path}",
                            code="FILE_NOT_FOUND",
                        )
                    query += " AND c.file_id = ?"
                    params.append(file_record["id"])
                if target_class:
                    query += " AND c.name = ?"
                    params.append(target_class)
                if line:
                    query += " AND m.line = ?"
                    params.append(line)
            else:
                db.disconnect()
                return ErrorResult(
                    message=f"Unknown entity type: {entity_type}",
                    code="INVALID_ENTITY_TYPE",
                )

            result = db.execute(query, tuple(params))
            rows = result.get("data", [])
            db.disconnect()

            entities = _normalize_entities(rows)
            if entities:
                return SuccessResult(
                    data={
                        "success": True,
                        "entity_type": entity_type,
                        "entity_name": entity_name,
                        "entities": entities,
                        "count": len(entities),
                    }
                )
            return ErrorResult(
                message=f"Entity not found: {entity_type} {entity_name}",
                code="ENTITY_NOT_FOUND",
            )
        except Exception as e:
            return self._handle_error(
                e, "GET_ENTITY_INFO_ERROR", "get_code_entity_info"
            )

